local function sendNewInfo(userId, className, infoKey, infoIndex)
    local dataStr = table.concat({ className, infoKey, infoIndex }, "'")
    if userId == "0" then
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            if player:checkReady() then
                CommonPacketSender:sendInfoNew(player.rakssid, dataStr)
            end
        end
    else
        local player = PlayerManager:getPlayerByUserId(userId)
        if player then
            CommonPacketSender:sendInfoNew(player.rakssid, dataStr)
        end
    end
end

---调整队伍人数
local function adjustTeamPlayerCount()
    local teams = { ["0"] = {} }
    for teamId, _ in pairs(TeamConfig:getTeams()) do
        teams[tostring(teamId)] = {}
    end
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        table.insert(teams[tostring(player.teamId)], tostring(player.userId))
    end
    ---扫描没队的玩家数量,把超出GameConfig.teamPlayers个人的队伍进行 人数调整.
    for teamId, _ in pairs(TeamConfig:getTeams()) do
        while #teams[tostring(teamId)] > GameConfig.teamPlayers do
            local morePlayerUserId = table.remove(teams[tostring(teamId)], #teams[tostring(teamId)])
            GameMatch.Teams[teamId]:subPlayer(morePlayerUserId)
            table.insert(teams["0"], morePlayerUserId)
        end
    end
    for _, userId in pairs(teams["0"]) do
        local morePlayer = PlayerManager:getPlayerByUserId(userId)
        if morePlayer then
            for teamId, _ in pairs(TeamConfig:getTeams()) do
                if #teams[tostring(teamId)] < GameConfig.teamPlayers then
                    table.insert(teams[tostring(teamId)], userId)
                    morePlayer.teamId = teamId
                    morePlayer:initTeam()
                    MessagesManage:sendSystemTipsToPlayer(morePlayer.rakssid, Messages:adjustTeamMsg(morePlayer))
                    break
                end
            end
        end
    end
    for _, player in pairs(players) do
        local team = GameMatch.Teams[player.teamId]
        if team then
            team.info:addPlayer(player.userId)
            for _, itemId in pairs(team.initItems) do
                player:addInitItems(itemId)
            end
        end
    end
    --if #players > 16 then
    --    print("[SCRIPT_EXCEPTION]------------------- More than 16 players. player count = " .. #players)
    --    for pos, player in pairs(players) do
    --        print("[" .. pos .. "][" .. tostring(player.userId) .. "]", "[name]=" .. player.name, "[followEnterType]=" .. player.dynamicAttr.followEnterType)
    --    end
    --end
end

GameInfoManager = class("GameInfoManager", BaseInfoManager)

local instance

function GameInfoManager.Instance()
    if not instance then
        instance = GameInfoManager.new()
    end
    return instance
end

function GameInfoManager:initInfo()
    adjustTeamPlayerCount()
    ---同步血量信息
    LuaTimer:scheduleTimer(function()
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            local healthPro = player:getHealth() / player:getMaxHealth()
            healthPro = math.floor(healthPro * 100) / 100
            player.info:setValue("blood", healthPro)
        end
    end, 100)
    self:onTick()
    ---队伍初始化好的同时, 不让玩家进入, 并且上报当前队伍信息
    HostApi.sendStartGame(PlayerManager:getPlayerCount())
    local userId = GameMatch:getOnePlayerUserId()
    if userId ~= nil then
        GameAnalytics:design(userId, 0, { "BedWarTeamInfo", TeamConfig:getTeamMaxMinDiff() })
    end
end

function GameInfoManager:register()

end

function GameInfoManager:onTick()
    local infoMap = self:getAllInfo()
    local changeInfoList = {}
    for _, info in pairs(infoMap) do
        local buildResult = info:buildChangePacket()
        if #buildResult > 0 then
            table.insert(changeInfoList, buildResult)
        end
    end

    ---如果有info的改变.
    if #changeInfoList > 0 then
        local result = table.concat(changeInfoList, "!")
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            if player:checkReady() then
                CommonPacketSender:sendInfoUpdate(player.rakssid, result)
            end
        end
    end
end

function GameInfoManager:newInfo(className, infoKey)
    local index = self.super.newInfo(self, className, infoKey)
    ---sync new Info
    sendNewInfo("0", className, infoKey, index)
end

function GameInfoManager:onPlayerReady(player)
    ---不管什么时候,玩家ready完就 将已经创建好的info同步下去
    local infoMap = self:getAllInfo()
    for infoIndex, info in pairs(infoMap) do
        sendNewInfo(tostring(player.userId), info.__cname, info.infoKey, infoIndex)
        CommonPacketSender:sendInfoUpdate(player.rakssid, info:buildAllPacket())
    end
    if GameMatch.allowPvp then
        ---游戏开始后
        player:onSpawnInGame()
        CommonPacketSender:sendGameStart(player.rakssid)
    end
end